<script>
    // Маска номера телефона
    document.querySelectorAll('input[type="phone"]').forEach(function (input) {
        Inputmask({
            mask: '+7 (999) 999-99-99',
            placeholder: '+7 (xxx) xxx-xx-xx',
            clearIncomplete: true,
            clearMaskOnLostFocus: true,
        }).mask(input);
    });
</script>
